def prime_fib(n: int):
    fib = [0, 1]
    primes = []

    while len(primes) < n:
        fib.append(fib[-1] + fib[-2])
        if fib[-1] > 1 and all(fib[-1] % i != 0 for i in range(2, int(fib[-1]**0.5) + 1)):
            primes.append(fib[-1])

    return primes[n - 1]
```

