def prime_fib(n: int):
    fibs = [0, 1]
    primes = []

    while len(primes) < n:
        next_fib = fibs[-1] + fibs[-2]
        fibs.append(next_fib)

        if next_fib > 1:
            is_prime = True
            for i in range(2, int(next_fib**0.5) + 1):
                if next_fib % i == 0:
                    is_prime = False
                    break
            if is_prime:
                primes.append(next_fib)

    return primes[n-1]
