def prime_fib(n: int):
    fibs = []
    a, b = 0, 1
    while len(fibs) < n:
        a, b = b, a + b
        if a > 1:
            for i in range(2, int(a**0.5) + 1):
                if a % i == 0:
                    break
            else:
                fibs.append(a)
    return fibs[-1]
```

```python
def prime_fib(n: int):
    fibs = []
    a, b = 0, 1
    while len(fibs) < n:
        a, b = b, a + b
        if a > 1 and all(a % i != 0 for i in range(2, int(a**0.5) + 1)):
            fibs.append(a)
    return fibs[-1]
```

